fun solve(nums: Array<Long>): Long {
    var maxSum = 0L
    val n = nums.size

    // Iterate all possible masks for A and B (each bit represents if the element is in A or B)
    // Since n is up to 19, 3^19 is manageable (around 1.16 billion), but it's too large.
    // So we need a smarter approach.

    // Alternative approach: iterate all possible non-empty B subsets, and then split remaining into A and C
    // But even that is O(3^n), which is feasible for n=19 (3^19 ~ 1.16 billion)
    // Given time constraints, we proceed with the O(3^n) approach

    // We'll represent the subsets as follows:
    // For each element, it can be in A (0), B (1), or C (2)
    // So we can represent the partition as a base-3 number

    val maxMask = Math.pow(3.0, n.toDouble()).toInt()

    for (mask in 0 until maxMask) {
        var currentMask = mask
        var xorA = 0L
        var andB = -1L // Initialized to all 1's (bitwise AND identity)
        var xorC = 0L
        var hasB = false

        for (i in 0 until n) {
            val part = currentMask % 3
            currentMask /= 3

            when (part) {
                0 -> xorA = xorA xor nums[i]
                1 -> {
                    andB = andB and nums[i]
                    hasB = true
                }
                2 -> xorC = xorC xor nums[i]
            }
        }

        // If B is empty, andB is 0
        val currentAndB = if (hasB) andB else 0L
        val currentSum = xorA + currentAndB + xorC
        if (currentSum > maxSum) {
            maxSum = currentSum
        }
    }

    return maxSum
}
