fun solve(nums: Array<Long>): Long {
    var maxSum = 0L
    val n = nums.size

    // Iterate all possible subsets for B
    for (mask in 0 until (1 shl n)) {
        val B = mutableListOf<Long>()
        val remaining = mutableListOf<Long>()

        for (i in 0 until n) {
            if ((mask and (1 shl i)) != 0) {
                B.add(nums[i])
            } else {
                remaining.add(nums[i])
            }
        }

        val andB = if (B.isEmpty()) 0L else B.reduce { acc, num -> acc and num }

        // Now, split remaining into A and C to maximize XOR(A) + XOR(C)
        val m = remaining.size
        var maxXorSum = 0L

        // Try all possible splits of remaining into A and C
        for (splitMask in 0 until (1 shl m)) {
            var xorA = 0L
            var xorC = 0L

            for (i in 0 until m) {
                if ((splitMask and (1 shl i)) != 0) {
                    xorA = xorA xor remaining[i]
                } else {
                    xorC = xorC xor remaining[i]
                }
            }

            val currentSum = xorA + xorC
            if (currentSum > maxXorSum) {
                maxXorSum = currentSum
            }
        }

        val total = andB + maxXorSum
        if (total > maxSum) {
            maxSum = total
        }
    }

    return maxSum
}
