fun solve(nums: Array<Long>): Long {
    val n = nums.size
    var maxSum = 0L

    // Iterate all possible masks for A and B (each bit represents if the element is in A or B)
    for (maskA in 0 until (1 shl n)) {
        for (maskB in 0 until (1 shl n)) {
            // Ensure no overlap between A and B
            if (maskA and maskB != 0) continue

            var xorA = 0L
            var andB = 0L.inv() // Initialize to all 1s for AND operation
            var xorC = 0L

            for (i in 0 until n) {
                val bit = 1 shl i
                if (maskA and bit != 0) {
                    xorA = xorA xor nums[i]
                } else if (maskB and bit != 0) {
                    andB = andB and nums[i]
                } else {
                    xorC = xorC xor nums[i]
                }
            }

            // Handle empty B case (AND is 0)
            if (maskB == 0) andB = 0L

            val currentSum = xorA + andB + xorC
            if (currentSum > maxSum) {
                maxSum = currentSum
            }
        }
    }

    return maxSum
}
