fun solve(nums: Array<Long>): Long {
    var maxSum = 0L
    val n = nums.size

    // Iterate all possible subsets for B (AND part)
    for (mask in 0 until (1 shl n)) {
        val aList = mutableListOf<Long>()
        val bList = mutableListOf<Long>()
        val cList = mutableListOf<Long>()

        for (i in 0 until n) {
            if (mask and (1 shl i) != 0) {
                bList.add(nums[i])
            } else {
                // We need to decide whether to put in A or C
                // So we need to try all possibilities for A and C
                // But since the order doesn't matter, we can just split the remaining elements
                // into A and C in all possible ways
                // But for efficiency, we can consider all possible splits of the remaining elements
                // into A and C
                // So we need another loop for the remaining elements
                // But this would be O(3^n) which is acceptable for n=19 (3^19 is ~1e9, which is too slow)
                // So we need a better approach
                // Alternatively, we can consider that for the remaining elements, the optimal is to put each element
                // either in A or C to maximize XOR(A) + XOR(C)
                // Since XOR(A) + XOR(C) is maximized when each element is in the set where it contributes the most
                // So for each element not in B, we can choose to put it in A or C to maximize the sum
                // So we can greedily assign each element to A or C based on which gives higher sum
                // So no need for another loop
                // So we can process the remaining elements one by one and decide to put in A or C
            }
        }

        // Now, for elements not in B, assign to A or C to maximize XOR(A) + XOR(C)
        var xorA = 0L
        var xorC = 0L
        for (i in 0 until n) {
            if (mask and (1 shl i) == 0) {
                val num = nums[i]
                if ((xorA xor num) + xorC > xorA + (xorC xor num)) {
                    xorA = xorA xor num
                } else {
                    xorC = xorC xor num
                }
            }
